# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : AppCompatActivity() {
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var executor: Executor
    private lateinit var sharedPreferences: SharedPreferences

    private lateinit var usernameEditText: EditText
    private lateinit var passwordEditText: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button
    private lateinit var statusTextView: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        sharedPreferences = getSharedPreferences("BiometricAuth", Context.MODE_PRIVATE)

        usernameEditText = findViewById(R.id.usernameEditText)
        passwordEditText = findViewById(R.id.passwordEditText)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)
        statusTextView = findViewById(R.id.statusTextView)

        if (isAuthenticated()) {
            navigateToMainActivity()
            return
        }

        executor = ContextCompat.getMainExecutor(this)

        setupBiometricPrompt()
        checkBiometricAvailability()

        loginButton.setOnClickListener {
            handlePasswordLogin()
        }

        biometricButton.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        applicationContext,
                        "Authentication error: $errString",
                        Toast.LENGTH_SHORT
                    ).show()
                    statusTextView.text = "Biometric authentication failed. Please use password."
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Toast.makeText(
                        applicationContext,
                        "Authentication succeeded!",
                        Toast.LENGTH_SHORT
                    ).show()
                    setAuthenticatedFlag(true)
                    navigateToMainActivity()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        applicationContext,
                        "Authentication failed. Try again.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Log in using your fingerprint or face")
            .setDescription("Place your finger on the sensor to authenticate")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(false)
            .build()
    }

    private fun checkBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
                    BiometricManager.Authenticators.BIOMETRIC_WEAK
        )) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricButton.isEnabled = true
                statusTextView.text = "Use biometric or password to login"
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                biometricButton.isEnabled = false
                statusTextView.text = "No biometric hardware available. Use password to login."
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                biometricButton.isEnabled = false
                statusTextView.text = "Biometric hardware unavailable. Use password to login."
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                biometricButton.isEnabled = false
                statusTextView.text = "No biometric enrolled. Use password to login."
            }
            else -> {
                biometricButton.isEnabled = false
                statusTextView.text = "Use password to login"
            }
        }
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun handlePasswordLogin() {
        val username = usernameEditText.text.toString()
        val password = passwordEditText.text.toString()

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please enter username and password", Toast.LENGTH_SHORT).show()
            return
        }

        if (validateCredentials(username, password)) {
            Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()
            setAuthenticatedFlag(true)
            navigateToMainActivity()
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show()
            statusTextView.text = "Login failed. Please try again."
        }
    }

    private fun validateCredentials(username: String, password: String): Boolean {
        return username == "user" && password == "password"
    }

    private fun setAuthenticatedFlag(authenticated: Boolean) {
        sharedPreferences.edit().putBoolean("is_authenticated", authenticated).apply()
        sharedPreferences.edit().putLong("auth_timestamp", System.currentTimeMillis()).apply()
    }

    private fun isAuthenticated(): Boolean {
        val isAuth = sharedPreferences.getBoolean("is_authenticated", false)
        val authTimestamp = sharedPreferences.getLong("auth_timestamp", 0)
        val currentTime = System.currentTimeMillis()
        val sessionTimeout = 24 * 60 * 60 * 1000

        return isAuth && (currentTime - authTimestamp) < sessionTimeout
    }

    private fun navigateToMainActivity() {
        val intent = Intent(this, MainActivity::class.java)
        startActivity(intent)
        finish()
    }
}

class MainActivity : AppCompatActivity() {
    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences("BiometricAuth", Context.MODE_PRIVATE)

        val logoutButton: Button = findViewById(R.id.logoutButton)
        val welcomeTextView: TextView = findViewById(R.id.welcomeTextView)

        welcomeTextView.text = "Welcome! You are authenticated."

        logoutButton.setOnClickListener {
            logout()
        }
    }

    private fun logout() {
        sharedPreferences.edit().clear().apply()
        val intent = Intent(this, LoginActivity::class.java)
        startActivity(intent)
        finish()
    }
}